    def __init__(self, numbers):
        self.numbers = numbers
        self.largest = -1

    def is_prime(self, n):
        if n < 2:
            return False
        for i in range(2, int(n**0.5) + 1):
            if n % i == 0:
                return False
        return True

    def largest_prime(self):
        for num in self.numbers:
            if self.is_prime(num) and num > self.largest:
                self.largest = num
        return self.largest
```
