```python
class PrimeNumberGenerator:
    def __init__(self, limit):
        self.limit = limit
        self.primes = []

    def is_prime(self, n):
        if n < 2:
            return False
        for i in range(2, int(n**0.5) + 1):
            if n % i == 0:
                return False
        return True

    def generate_primes(self):
        for num in range(2, self.limit + 1):
            if self.is_prime(num):
                self.primes.append(num)
        return self.primes
