## 🧠 Shader Concept

We'll create a **Surface Shader** that applies a **pulsing color effect** using the `time` variable. The pulsing effect will be based on the **vertex position** (for spatial mapping) or **UV** (if available).

---

## ✅ Example: URP Surface Shader with Pulsing Effect

```hlsl
// Shader Graph or Surface Shader version
// This is a Surface Shader for URP, using the Standard Surface Shader model.

Shader "URP/PulsingEffect"
{
    Properties
    {
        _Color ("Color", Color) = (1,1,1,1)
        _PulseSpeed ("Pulse Speed", Float) = 1.0
        _PulseAmount ("Pulse Amount", Float) = 0.5
        _GlowColor ("Glow Color", Color) = (0,1,0,1)
    }
    SubShader
    {
        Tags { "RenderType"="Opaque" "RenderPipeline"="UniversalRenderPipeline" }
        LOD 200

        Pass
        {
            Name "ForwardLit"
            Tags { "LightMode"="UniversalForward" }

            HLSLPROGRAM
            #pragma vertex vert
            #pragma fragment frag
            #pragma multi_compile_fwdbase
            #pragma target 4.5

            #include "UnityCG.hlsl"
            #include "Lighting.hlsl"
            #include "UnityDeferredLibrary.hlsl"
            #include "UnityShaderGraphFunctions.hlsl"

            struct appdata
            {
                float4 vertex : POSITION;
                float2 uv : TEXCOORD0;
            };

            struct v2f
            {
                float2 uv : TEXCOORD0;
                float4 pos : SV_POSITION;
                float3 worldPos : WORLDPOS;
            };

            CBUFFER_START(UnityPerMaterial)
            float4 _Color;
            float _PulseSpeed;
            float _PulseAmount;
            float4 _GlowColor;
            CBUFFER_END

            float3 GetPulseEffect(float3 worldPos)
            {
                float pulse = sin(_Time.y * _PulseSpeed) * _PulseAmount;
                return _GlowColor.rgb * (1.0 + pulse);
            }

            v2f vert (appdata v)
            {
                v2f o;
                o.pos = UnityObjectToClipPos(v.vertex);
                o.uv = v.uv;
                o.worldPos = mul(unity_ObjectToWorld, v.vertex).xyz;
                return o;
            }

            float4 frag (v2f i) : SV_Target
            {
                float3 worldPos = i.worldPos;
                float3 pulseColor = GetPulseEffect(worldPos);

                // Base color
                float3 baseColor = _Color.rgb;

                // Combine with pulse
                float3 finalColor = lerp(baseColor, pulseColor, _PulseAmount);

                return float4(finalColor, 1.0);
            }
            ENDHLSL
        }
    }
}
